mapper.select:
/* kr.or.ddit.common.sms.mapper.ISmsMapper.selectNextSmsNo */
/* SMS 발송번호 생성 */

SELECT 'SMS' || LPAD(SEQ_SMS_SND.NEXTVAL, 6, '0')
FROM DUAL

/* kr.or.ddit.common.sms.mapper.ISmsMapper.selectNextSmsDtlNo */
/* SMS 발송상세번호 생성 */

SELECT 'SMD' || LPAD(SEQ_SMS_SND_DTL.NEXTVAL, 6, '0')
FROM DUAL

/* kr.or.ddit.common.sms.mapper.ISmsMapper.selectReceiverByUserNo */
/* 회원번호로 SMS 수신자 조회 */

SELECT
    USER_NO AS userNo,
    USER_TELNO AS userTel
FROM MEMBER
WHERE USER_NO = #{userNo}
  AND USER_YN = 'Y'
  AND SMS_RCV_YN = 'Y'
